import React, { useState, useEffect } from 'react';
import { ShieldCheckIcon, LeafIcon, LockIcon, XIcon } from '../components/icons/Icons';

// --- CONFIGURACIÓN ---
// AQUÍ PUEDES CAMBIAR EL CÓDIGO DE 8 DÍGITOS
const VALID_CODES = ['12345678', 'SUELO2025']; 
const TRIAL_DAYS = 7;

interface PremiumGateProps {
    children: React.ReactNode;
    featureName: string; // 'Dr. Plantas' o 'Chatbot'
    isEmbedded?: boolean; // Si es true, se ajusta al tamaño del contenedor (para el chatbot)
}

const PremiumGate: React.FC<PremiumGateProps> = ({ children, featureName, isEmbedded = false }) => {
    const [accessStatus, setAccessStatus] = useState<'loading' | 'granted' | 'locked'>('loading');
    const [inputCode, setInputCode] = useState('');
    const [error, setError] = useState<string | null>(null);
    const [daysLeft, setDaysLeft] = useState(0);

    useEffect(() => {
        checkAccess();
    }, []);

    const checkAccess = () => {
        // 1. Revisar si ya tiene premium activado
        const isPremium = localStorage.getItem('suelo_urbano_premium_activated') === 'true';
        if (isPremium) {
            setAccessStatus('granted');
            return;
        }

        // 2. Revisar lógica de prueba gratuita
        const firstVisit = localStorage.getItem('suelo_urbano_first_visit');
        let visitDate;

        if (!firstVisit) {
            // Si es la primera vez que se ejecuta este chequeo, guardamos la fecha
            visitDate = Date.now();
            localStorage.setItem('suelo_urbano_first_visit', visitDate.toString());
        } else {
            visitDate = parseInt(firstVisit);
        }

        const now = Date.now();
        const diffTime = Math.abs(now - visitDate);
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        const remaining = TRIAL_DAYS - diffDays;

        if (remaining >= 0) {
            setDaysLeft(remaining);
            setAccessStatus('granted');
        } else {
            setAccessStatus('locked');
        }
    };

    const handleUnlock = (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);

        if (VALID_CODES.includes(inputCode.trim())) {
            localStorage.setItem('suelo_urbano_premium_activated', 'true');
            setAccessStatus('granted');
        } else {
            setError('Código incorrecto. Verifica los 8 dígitos en tu producto.');
        }
    };

    if (accessStatus === 'loading') return null;

    // Si el acceso está concedido, mostramos el contenido
    if (accessStatus === 'granted') {
        return (
            <div className={`relative ${isEmbedded ? 'h-full flex flex-col' : ''}`}>
                {/* Pequeña insignia de prueba si aplica */}
                {daysLeft > 0 && localStorage.getItem('suelo_urbano_premium_activated') !== 'true' && (
                    <div className="absolute top-0 right-0 z-10 bg-yellow-400 text-yellow-900 text-[10px] font-bold px-2 py-1 rounded-bl-lg shadow-sm pointer-events-none">
                        Prueba: {daysLeft} días restantes
                    </div>
                )}
                {children}
            </div>
        );
    }

    // INTERFAZ DE BLOQUEO (PREMIUM GATE)
    return (
        <div className={`flex flex-col items-center justify-center text-center p-6 bg-white dark:bg-stone-800 border border-stone-200 dark:border-stone-700 rounded-2xl shadow-xl ${isEmbedded ? 'h-full w-full absolute inset-0 z-50' : 'min-h-[400px]'}`}>
            <div className="bg-green-100 dark:bg-green-900/50 p-4 rounded-full mb-4 animate-bounce-float">
                <LockIcon className="h-10 w-10 text-green-700 dark:text-green-400" />
            </div>

            <h3 className="text-2xl font-bold text-stone-800 dark:text-stone-100 mb-2">
                Acceso Premium Requerido
            </h3>

            <p className="text-stone-600 dark:text-stone-300 mb-6 max-w-md">
                Tu prueba gratuita de <strong>{featureName}</strong> ha terminado. Para continuar disfrutando de esta herramienta, introduce el código de 8 dígitos que viene con tu <strong>Emulsión Suelo Urbano</strong>.
            </p>

            <form onSubmit={handleUnlock} className="w-full max-w-xs space-y-4">
                <div>
                    <input 
                        type="text" 
                        value={inputCode}
                        onChange={(e) => setInputCode(e.target.value)}
                        placeholder="Código (Ej: 12345678)"
                        maxLength={8}
                        className="w-full px-4 py-3 text-center text-lg tracking-widest font-mono border-2 border-stone-300 rounded-lg focus:border-green-500 focus:ring-green-500 dark:bg-stone-700 dark:border-stone-600 dark:text-white uppercase"
                    />
                </div>

                {error && (
                    <p className="text-red-500 text-sm font-medium flex items-center justify-center gap-1">
                        <XIcon className="h-4 w-4" /> {error}
                    </p>
                )}

                <button 
                    type="submit"
                    className="w-full bg-green-600 text-white font-bold py-3 px-6 rounded-lg hover:bg-green-700 transition-all shadow-lg flex items-center justify-center gap-2"
                >
                    <ShieldCheckIcon className="h-5 w-5" />
                    Desbloquear Acceso
                </button>
            </form>

            <p className="mt-6 text-xs text-stone-400 dark:text-stone-500">
                ¿No tienes un código? Adquiere nuestra emulsión para obtener acceso ilimitado.
                <br/>
                <a href="#/pedido" className="text-green-600 hover:underline dark:text-green-400 mt-1 inline-block">Comprar ahora</a>
            </p>
        </div>
    );
};

export default PremiumGate;

import * as React from 'react';
// Imports for components in Root
import Header from './components/Header';
import Hero from './components/Hero';
import BenefitsSection from './components/BenefitsSection';
import UsageSection from './components/UsageSection';
import Footer from './components/Footer';
import EmulsionExplainedSection from './components/EmulsionExplainedSection';
import OrderPage from './components/OrderPage';
import UtilitiesPage from './components/UtilitiesPage';
import CompositionPage from './components/CompositionPage';
import WateringGuidePage from './components/WateringGuidePage';
import PlantDoctorPage from './components/PlantDoctorPage';
import HowToUsePage from './components/HowToUsePage';
import LocationsPage from './components/LocationsPage';
import DonationPage from './components/DonationPage';
import FallingLeaves from './components/FallingLeaves';
import WelcomeSplash from './components/WelcomeSplash';
import FloatingDonationButton from './components/FloatingDonationButton';
import VideoIntro from './components/VideoIntro';
import Chatbot from './components/Chatbot';
import CompostInfoSection from './components/CompostInfoSection';
import PlantCareGuideSection from './components/PlantCareGuideSection';
import PhInfoSection from './components/PhInfoSection';
import CuriousFactPopup from './components/CuriousFactPopup';

// Declara la función global gtag para que TypeScript la reconozca
declare global {
  interface Window {
    gtag: (command: string, action: string, params?: { [key: string]: any }) => void;
  }
}

const HomePage: React.FC = () => {
    return (
        <div className="min-h-screen flex flex-col bg-gray-50 dark:bg-gray-900">
            <main className="flex-grow">
                <Hero onOrderClick={() => { window.location.hash = '#/pedido'; }} />

                <div className="relative">
                    <FallingLeaves position="absolute" />

                    <div id="que-es">
                        <EmulsionExplainedSection />
                    </div>

                    <div id="beneficios">
                        <BenefitsSection />
                    </div>

                    <div id="guia-cuidados">
                        <PlantCareGuideSection />
                    </div>

                    <div id="info-ph">
                        <PhInfoSection />
                    </div>

                    <div id="modo-uso">
                        <UsageSection />
                    </div>

                    <div id="composta">
                        <CompostInfoSection />
                    </div>
                </div>
            </main>
            <Footer />
        </div>
    );
};

const getCurrentHash = () => window.location.hash || '#';

type AppState = 'splash' | 'video' | 'home';

const App: React.FC = () => {
  const [route, setRoute] = React.useState(getCurrentHash());
  const [appState, setAppState] = React.useState<AppState>('splash');
  const [showFactPopup, setShowFactPopup] = React.useState(false);

  // Inicializar contador de prueba gratuita si no existe
  React.useEffect(() => {
    const firstVisit = localStorage.getItem('suelo_urbano_first_visit');
    if (!firstVisit) {
        localStorage.setItem('suelo_urbano_first_visit', Date.now().toString());
    }
  }, []);

  React.useEffect(() => {
    const handleHashChange = () => {
      const newRoute = getCurrentHash();
      setRoute(newRoute);
      window.scrollTo(0, 0);
      if (typeof window.gtag === 'function') {
        window.gtag('event', 'page_view', {
          page_path: newRoute,
          page_location: window.location.href,
        });
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    return () => {
      window.removeEventListener('hashchange', handleHashChange);
    };
  }, []);

  // Lógica del temporizador para Datos Curiosos
  React.useEffect(() => {
    let intervalId: number;

    if (appState === 'home') {
        // Configurar el intervalo para que se ejecute cada 2 minutos (120,000 ms)
        // Se puede ajustar a 30000 (30 seg) para pruebas rápidas
        intervalId = window.setInterval(() => {
            // Solo mostrar si no hay otro modal intrusivo abierto (por ahora asumimos que no)
            // y si el popup no está ya visible
            setShowFactPopup(prev => !prev ? true : prev);
        }, 120000); 
    }

    return () => {
        if (intervalId) clearInterval(intervalId);
    };
  }, [appState]);

  const handleEnterSplash = () => {
    const hasSeenVideo = localStorage.getItem('hasSeenIntroVideo');
    if (hasSeenVideo) {
      setAppState('home');
    } else {
      setAppState('video');
    }
  };

  const handleVideoComplete = () => {
    localStorage.setItem('hasSeenIntroVideo', 'true');
    setAppState('home');
  };

  let pageContent;
  let isHomePage = false;

  const renderHeader = (isHome = false) => {
    const scrollTo = (id: string) => {
      if (id === 'inicio') {
        window.scrollTo({ top: 0, behavior: 'smooth' });
        return;
      }
      const element = document.getElementById(id);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    };
    return <Header onNavigate={isHome ? scrollTo : undefined} isHomePage={isHome} />;
  };

  switch (route) {
    case '#/pedido':
      pageContent = <OrderPage header={renderHeader()} />;
      break;
    case '#/utilidades':
      pageContent = <UtilitiesPage header={renderHeader()} />;
      break;
    case '#/composicion':
      pageContent = <CompositionPage header={renderHeader()} />;
      break;
    case '#/guia-riego':
      pageContent = <WateringGuidePage header={renderHeader()} />;
      break;
    case '#/doctor-plantas':
      pageContent = <PlantDoctorPage header={renderHeader()} />;
      break;
    case '#/guia-interactiva':
      pageContent = <HowToUsePage header={renderHeader()} />;
      break;
    case '#/puntos-de-venta':
      pageContent = <LocationsPage header={renderHeader()} />;
      break;
    case '#/donar':
      pageContent = <DonationPage header={renderHeader()} />;
      break;
    case '#/donacion-exitosa':
      window.location.hash = '#';
      pageContent = <HomePage />;
      isHomePage = true;
      break;
    default:
      pageContent = <HomePage />;
      isHomePage = true;
      break;
  }

  return (
      <div className="relative font-sans text-gray-800 dark:text-gray-100">
        {/* Main Content Wrapper - gets blurred */}
        <div className={`transition-all duration-500 ${appState === 'video' ? 'blur-md brightness-75 pointer-events-none' : ''}`}>
            <div className="fixed inset-0 bg-gray-50 dark:bg-gray-900 -z-20" />

            {/* Content that is part of the page and should be blurred */}
            <div className={appState === 'splash' ? 'opacity-0' : (appState === 'home' ? 'animate-fade-in-main' : 'opacity-100')}>
                {appState === 'home' && !isHomePage && <FallingLeaves position="fixed" />}
                {appState === 'home' && isHomePage && <FloatingDonationButton />}

                {isHomePage ? renderHeader(true) : null}
                {pageContent}
            </div>
        </div>

        {/* Overlays that are not blurred */}
        {/* Chatbot: Solo visible en HomePage y cuando el estado es 'home' (no splash/video) */}
        {isHomePage && appState === 'home' && <Chatbot />}

        <CuriousFactPopup isVisible={showFactPopup} onClose={() => setShowFactPopup(false)} />

        {appState === 'splash' && <WelcomeSplash onEnter={handleEnterSplash} />}
        {appState === 'video' && <VideoIntro onComplete={handleVideoComplete} />}
      </div>
  );
};

export default App;
